import{_ as a,o as t,c as o,a4 as d}from"./chunks/framework.4M7SpZrd.js";const p=JSON.parse('{"title":"Painel de Agentes IA — Dashboard KAAS","description":"","frontmatter":{},"headers":[],"relativePath":"admin/agents-dashboard.md","filePath":"admin/agents-dashboard.md"}'),s={name:"admin/agents-dashboard.md"};function r(n,e,i,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="painel-de-agentes-ia-—-dashboard-kaas" tabindex="-1">Painel de Agentes IA — Dashboard KAAS <a class="header-anchor" href="#painel-de-agentes-ia-—-dashboard-kaas" aria-label="Permalink to &quot;Painel de Agentes IA — Dashboard KAAS&quot;">​</a></h1><p>Gerenciamento centralizado dos 10 agentes IA que operam o Kubex, com monitoramento em tempo real, mensagens inter-agentes, logs de execucao e controles operacionais.</p><p><strong>Acesso:</strong> <code>http://admin.kubex.test/agentes</code> (dev) | <code>https://admin.kubex.com.br/agentes</code> (prod)</p><p>Para descricao detalhada de cada agente (papeis, modelos, frequencias), ver <a href="./../agentes/">KAAS Documentacao</a>.</p><hr><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+----------------------------------------------------------+</span></span>
<span class="line"><span>|  Painel de Agentes IA (KAAS)                             |</span></span>
<span class="line"><span>|----------------------------------------------------------|</span></span>
<span class="line"><span>|  [Header Stats] Ativos: 10/10 | Custo: $2.50 | Pendentes: 2 | Kill Switch |</span></span>
<span class="line"><span>|  [Agent Cards Grid] 10 cards com status, modelo, custo   |</span></span>
<span class="line"><span>|  [Run Agent + Timeline] Instrucao customizada + acoes     |</span></span>
<span class="line"><span>|  [Approval Queue] Aprovacoes pendentes (CEO)              |</span></span>
<span class="line"><span>|  [Custos por Agente] Tabela: hoje, mes, restante, calls   |</span></span>
<span class="line"><span>|  [Mensagens] Filtros: periodo, agente, expandir, TTL      |</span></span>
<span class="line"><span>|  [Terminal KAAS] Logs SSE em tempo real                    |</span></span>
<span class="line"><span>+----------------------------------------------------------+</span></span></code></pre></div><hr><h2 id="_1-header-stats" tabindex="-1">1. Header Stats <a class="header-anchor" href="#_1-header-stats" aria-label="Permalink to &quot;1. Header Stats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metrica</th><th>Descricao</th><th>Alerta</th></tr></thead><tbody><tr><td><strong>Agentes Ativos</strong></td><td>Quantos dos 10 agentes estao <code>is_active=true</code></td><td>&gt; 2 inativos: investigar</td></tr><tr><td><strong>Custo Hoje</strong></td><td>Soma de <code>cost_today_usd</code></td><td>&gt; $30: pausar agentes nao-criticos</td></tr><tr><td><strong>Aprovacoes Pendentes</strong></td><td>Count de <code>AgentApproval</code> com <code>decision=NULL</code></td><td>&gt; 0: requer acao do CEO</td></tr><tr><td><strong>Kill Switch</strong></td><td>Emergencia: <code>kubex:kaas:kill_switch</code></td><td>Ativo = todos agentes param</td></tr></tbody></table><p><strong>Kill Switch:</strong> Pausa todos os agentes imediatamente. KAAS Scheduler nao dispara novas execucoes. Agentes nao respondem a mensagens (exceto CEO override).</p><hr><h2 id="_2-agent-cards" tabindex="-1">2. Agent Cards <a class="header-anchor" href="#_2-agent-cards" aria-label="Permalink to &quot;2. Agent Cards&quot;">​</a></h2><p>Grade de 10 cards. Cada card exibe: toggle ativo/inativo, descricao do papel, status badge, modelo, ultima execucao, proxima execucao, horario de operacao, custo hoje, falhas consecutivas.</p><h3 id="status-badge" tabindex="-1">Status Badge <a class="header-anchor" href="#status-badge" aria-label="Permalink to &quot;Status Badge&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Significado</th></tr></thead><tbody><tr><td><code>idle</code></td><td>Aguardando proximo ciclo</td></tr><tr><td><code>running</code></td><td>Executando agora</td></tr><tr><td><code>error</code></td><td>Ultima execucao falhou</td></tr><tr><td><code>paused</code></td><td>Desativado manualmente</td></tr><tr><td><code>disabled</code></td><td>Desabilitado pelo kill switch</td></tr></tbody></table><hr><h2 id="_3-run-agent-timeline" tabindex="-1">3. Run Agent + Timeline <a class="header-anchor" href="#_3-run-agent-timeline" aria-label="Permalink to &quot;3. Run Agent + Timeline&quot;">​</a></h2><h3 id="executar-agora" tabindex="-1">Executar Agora <a class="header-anchor" href="#executar-agora" aria-label="Permalink to &quot;Executar Agora&quot;">​</a></h3><ol><li>Selecionar agente no grid</li><li>Digitar instrucao customizada (opcional — em branco executa workflow padrao)</li><li>Clicar [Executar Agora]</li><li>Agente inicia em background (pool de workers)</li><li>Timeline atualiza em tempo real</li></ol><h3 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h3><p>Ultimas 20 acoes do agente selecionado. Colunas: timestamp (HH:MM), status badge (success/running/error), descricao, duracao, modelo. Clicar numa acao expande o relatorio completo.</p><hr><h2 id="_4-approval-queue" tabindex="-1">4. Approval Queue <a class="header-anchor" href="#_4-approval-queue" aria-label="Permalink to &quot;4. Approval Queue&quot;">​</a></h2><p>Decisoes do CEO sobre operacoes propostas pelos agentes. Cada item exibe: nivel de risco, descricao, contexto, botoes [Aprovar] e [Rejeitar].</p><p><strong>Niveis de risco:</strong></p><table tabindex="0"><thead><tr><th>Nivel</th><th>Cor</th><th>Descricao</th></tr></thead><tbody><tr><td>critical</td><td>Vermelho</td><td>Operacao destrutiva</td></tr><tr><td>high</td><td>Laranja</td><td>Impacto significativo</td></tr><tr><td>medium</td><td>Amarelo</td><td>Impacto moderado</td></tr><tr><td>low</td><td>Verde</td><td>Impacto minimo</td></tr></tbody></table><hr><h2 id="_5-custos-por-agente" tabindex="-1">5. Custos por Agente <a class="header-anchor" href="#_5-custos-por-agente" aria-label="Permalink to &quot;5. Custos por Agente&quot;">​</a></h2><p>Tabela com colunas: Agente, Hoje ($), Mes ($), Restante ($), Calls.</p><ul><li><strong>Hoje</strong> — <code>kubex:kaas:cost:{agente}:{YYYY-MM-DD}</code></li><li><strong>Mes</strong> — Custo acumulado do mes corrente</li><li><strong>Restante</strong> — <code>daily_budget_usd - cost_today</code> (negativo = excedido)</li><li><strong>Calls</strong> — Numero de execucoes hoje</li></ul><hr><h2 id="_6-mensagens-entre-agentes" tabindex="-1">6. Mensagens entre Agentes <a class="header-anchor" href="#_6-mensagens-entre-agentes" aria-label="Permalink to &quot;6. Mensagens entre Agentes&quot;">​</a></h2><h3 id="filtros" tabindex="-1">Filtros <a class="header-anchor" href="#filtros" aria-label="Permalink to &quot;Filtros&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Filtro</th><th>Opcoes</th></tr></thead><tbody><tr><td><strong>Periodo</strong></td><td>Ultimas 24h, Ultimos 7 dias, Todas</td></tr><tr><td><strong>Agente</strong></td><td>Todos, SRE, Director, Docs, Backend, etc.</td></tr></tbody></table><h3 id="tipos-de-mensagem" tabindex="-1">Tipos de Mensagem <a class="header-anchor" href="#tipos-de-mensagem" aria-label="Permalink to &quot;Tipos de Mensagem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tipo</th><th>Badge</th><th>Descricao</th></tr></thead><tbody><tr><td><code>task_request</code></td><td>[Tarefa]</td><td>Um agente pedindo outro fazer algo</td></tr><tr><td><code>status_update</code></td><td>[Status]</td><td>Relatorio de progresso</td></tr><tr><td><code>escalation</code></td><td>[Escalacao]</td><td>Problema que precisa de CEO</td></tr><tr><td><code>conflict</code></td><td>[Conflito]</td><td>Dois agentes querem mesmo recurso</td></tr></tbody></table><h3 id="prioridade" tabindex="-1">Prioridade <a class="header-anchor" href="#prioridade" aria-label="Permalink to &quot;Prioridade&quot;">​</a></h3><p><code>critical</code> (vermelho), <code>high</code> (laranja), <code>normal</code> (azul), <code>low</code> (cinza).</p><h3 id="ttl" tabindex="-1">TTL <a class="header-anchor" href="#ttl" aria-label="Permalink to &quot;TTL&quot;">​</a></h3><p>Mensagens expiram apos 7 dias (168 horas). Indicador de tempo restante: vermelho (&lt; 24h), amarelo (&lt; 72h), cinza (&gt; 3 dias).</p><p>Clique em qualquer mensagem para expandir texto completo com formatacao Markdown.</p><hr><h2 id="_7-terminal-kaas" tabindex="-1">7. Terminal KAAS <a class="header-anchor" href="#_7-terminal-kaas" aria-label="Permalink to &quot;7. Terminal KAAS&quot;">​</a></h2><p>Logs em tempo real via SSE (Server-Sent Events). Levels: INFO (verde), WARN (amarelo), ERROR (vermelho), DEBUG (cinza, dev only). Auto-scroll ativo.</p><hr><h2 id="_8-api-dos-agentes" tabindex="-1">8. API dos Agentes <a class="header-anchor" href="#_8-api-dos-agentes" aria-label="Permalink to &quot;8. API dos Agentes&quot;">​</a></h2><h3 id="get-v1-admin-agents" tabindex="-1">GET /v1/admin/agents/ <a class="header-anchor" href="#get-v1-admin-agents" aria-label="Permalink to &quot;GET /v1/admin/agents/&quot;">​</a></h3><p>Retorna lista de agentes com: id, slug, name, persona_name, role, model, fallback_model, frequency_minutes, schedule_start/end, is_active, sandbox_mode, daily_budget_usd, status, last_run_at, next_run_at, total_cost_usd, consecutive_failures. Inclui <code>kill_switch_active</code> e <code>total_cost_today_usd</code>.</p><h3 id="get-v1-admin-agents-slug-actions" tabindex="-1">GET /v1/admin/agents/{slug}/actions <a class="header-anchor" href="#get-v1-admin-agents-slug-actions" aria-label="Permalink to &quot;GET /v1/admin/agents/{slug}/actions&quot;">​</a></h3><p>Retorna ultimas acoes do agente: id, action_type, description, status, model_used, cost_input_tokens, cost_output_tokens, duration_ms, created_at.</p><h3 id="get-v1-admin-agents-messages" tabindex="-1">GET /v1/admin/agents/messages <a class="header-anchor" href="#get-v1-admin-agents-messages" aria-label="Permalink to &quot;GET /v1/admin/agents/messages&quot;">​</a></h3><p><strong>Query Params:</strong></p><table tabindex="0"><thead><tr><th>Param</th><th>Tipo</th><th>Default</th><th>Descricao</th></tr></thead><tbody><tr><td><code>limit</code></td><td>1-200</td><td>50</td><td>Quantidade de mensagens</td></tr><tr><td><code>hours</code></td><td>1-168</td><td>-</td><td>Filtrar pelos ultimos N horas</td></tr><tr><td><code>priority</code></td><td>str</td><td>-</td><td>low, normal, high, critical</td></tr><tr><td><code>msg_type</code></td><td>str</td><td>-</td><td>task_request, status_update, escalation, conflict</td></tr></tbody></table><p>TTL: mensagens expiram apos 7 dias (168 horas).</p><hr><h2 id="_9-troubleshooting" tabindex="-1">9. Troubleshooting <a class="header-anchor" href="#_9-troubleshooting" aria-label="Permalink to &quot;9. Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problema</th><th>Solucao</th></tr></thead><tbody><tr><td>Painel nao carrega</td><td>Verificar autenticacao admin, testar <code>GET /api/v1/admin/agents/</code></td></tr><tr><td>Mensagens nao aparecem</td><td>Verificar <code>is_active=true</code>, Redis keys <code>kubex:kaas:*</code>, aguardar SSE (ate 5s)</td></tr><tr><td>Timeline vazio</td><td>Agente ainda nao executado ou historico limpo (retencao: 90 dias)</td></tr><tr><td>Kill Switch nao responde</td><td>Verificar Redis: <code>get kubex:kaas:kill_switch</code>, reiniciar Redis</td></tr></tbody></table><hr><h2 id="_10-referencias" tabindex="-1">10. Referencias <a class="header-anchor" href="#_10-referencias" aria-label="Permalink to &quot;10. Referencias&quot;">​</a></h2><ul><li><a href="./../agentes/">KAAS Documentacao</a></li><li><a href="./../agentes/operacao">Operacao de Agentes</a></li></ul>`,61)])])}const g=a(s,[["render",r]]);export{p as __pageData,g as default};
